    message: `Explain this payslip: ${JSON.stringify(data)}`
  })),
  recommendLeave: data => unwrap(api.post('/ai/chat', {
    message: `Recommend leave for: ${JSON.stringify(data)}`
  })),
  suggestGoals: data => unwrap(api.post('/ai/chat', {
    message: `Suggest performance goals for: ${JSON.stringify(data)}`
  })),
