export const perfAPI = {
  cycles: () => Promise.resolve({
    data: []
  }),
  activeCycle: () => Promise.resolve({
    data: null
  }),
  myGoals: () => Promise.resolve({
    data: []
  }),
  allGoals: () => Promise.resolve({
    data: []
  }),
  submitGoals: () => Promise.resolve({
    data: {}
  }),
  createCycle: () => Promise.resolve({
    data: {}
  }),
  closeCycle: () => Promise.resolve({
    data: {}
  })
